INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f0899a01-moex-00227', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-13504c0c', 'sub-aboriginal-f0899a01-06', NULL, 'single_choice', '「醫藥之父希波克拉底（西元前460年－前370年）曾譽接骨木為天然醫藥箱，認為 它是自然界最偉大的治癒植物之一。美洲原住民將其用來調理各種肌膚問題；歐洲 人將它視為生活萬靈丹，大人小孩感冒或換季不適時會在溫涼的接骨木茶裡加入蜂 蜜飲用，舒緩不適感，也是最好的眼睛保養香草之一。還可用來熬煮成果醬、糖漿 和製作甜點。」 根據上文，下列選項何者正確？', '["接骨木被視為天然醫藥箱，因能延年益壽抗老化", "接骨木可應用在醫藥生技、身體保健與甜點食用", "野生的接骨木混合蜂蜜，能有效治療感冒與流感", "最早發現接骨木功效並加以應用的是美洲原住民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00228', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-13504c0c', 'sub-aboriginal-f0899a01-06', NULL, 'single_choice', '「撰寫講稿，難的是在於如何精準傳達要藉由致詞場合所釋放的訊息，不只是遣詞用 字必須精準，邏輯鋪陳必須正確，同時還要顧及總統的口語發音，以及總統身分的 高度。除此之外，最要掌握的是文氣，因著場合的不同，總統的致詞或要氣勢磅礴， 或要溫暖動人，除了讓在場的聽眾感受到之外，更必須讓透過書面媒體閱讀的廣大 受眾也能體會得到文字中所包涵的力量。而這也是我常常必須動手修改諸多長官與 學者專家所撰擬的文稿，最主要的原因。」 下列選項，最符合本文意旨的是：', '["總統的講稿，需要特別加強氣勢磅礴的力量", "講稿必須考量場合、對象及口語或書面應用", "文稿的修改，是在檢視是否符合應用文體例", "口語講稿和書面文稿，用詞應該保有一致性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00229', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '重要憲政機關之職位任期必須有所限制，以便人民有機會於一定時間內，重新決定對這些機關之授權。 此為何種憲法原則之內涵？', '["多黨競爭原則", "民主正當性原則", "權力分立原則", "法治國原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00230', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依憲法及相關司法院大法官解釋，有關軍事與國防，下列敘述何者正確？', '["總統統率全國陸海空軍，全國陸海空軍須效忠總統，保護人民", "國防與軍事事項，由中央立法，地方執行之", "軍事審判機關所行使者，亦屬國家刑罰權之一種，具有司法權之性質", "現役與退役軍人，均不得兼任文官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00231', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依司法院釋字第445號解釋意旨，集會自由與言論、講學、著作及出版自由，同屬下列何者之範疇？', '["表演自由", "表現自由", "人身自由", "行為自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00232', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '有關結社自由之限制，依司法院大法官解釋，下列敘述何者錯誤？', '["結社自由保障人民團體成立時之命名權及嗣後之更名權", "內政部以行政命令規定「人民團體經主管機關限期整理者，其理監事之職權應即停止」，違反法律 保留原則", "基於國家安全理由，主張共產主義或分裂國土之結社，不受憲法上結社自由之保障", "人民團體法規定職業團體理事長應「由理事就常務理事中選舉之，不設常務理事者，就理事中互選 之」，違反比例原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00233', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依司法院大法官解釋意旨，關於職業自由之敘述，下列何者錯誤？', '["醫師法將醫師區分為醫師、中醫師及牙醫師，禁止不具有醫師資格之中醫師以「限醫師指示使用」 之西藥處方為人治病等規定，大法官認為尚屬合憲", "「航空人員體格檢查標準」禁止不合格之民航技師繼續執業之規定，大法官認為係屬對其選擇職業 自由之客觀條件限制，且已違反比例原則而違憲", "藥事法限制醫師藥品調劑權之規定，大法官認為並未牴觸憲法保障人民工作權及比例原則等規定意 旨，尚屬合憲", "道路交通管理處罰條例不問計程車駕駛人之犯行是否足以顯示對乘客安全具有實質風險，均吊扣其 執業登記證、廢止其執業登記之規定，大法官認為對駕駛人工作權之限制已違反比例原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00234', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '訴訟救濟應循之審級、程序及相關要件，原則上應由何機關衡量訴訟案件之種類、性質、訴訟政策目 的，以及訴訟制度之功能等因素，為正當合理之規定？', '["各級法院", "行政院", "立法院", "憲法法庭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00235', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依憲法規定及司法院釋字第626號解釋，人民因有「受國民教育之權利」，故國家對人民有下列何種 義務？', '["提供受國民教育後之就業保障", "提供國民教育所需書籍", "對逾學齡未受基本教育者，提供補習教育", "保障人民有是否接受國民教育之選擇權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00236', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依司法院大法官解釋，有關道路交通管理處罰條例第37條第3項限制計程車駕駛人於執業期中犯特 定之罪者，3年內不得執業，且吊銷其持有之各級駕照之規定，下列敘述何者錯誤？', '["其法律要件，不符比例原則，侵害工作權", "其法律要件，不符比例原則，侵害人身自由", "有關吊銷駕駛執照部分，不符比例原則，侵害工作權", "有關吊銷駕駛執照部分，不符比例原則，侵害一般行為自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
